# For async calls with per-request tracing
import asyncio

async def traced_call(question: str, user_id: str) -> str:
    return await chain.ainvoke(
        {"topic": question},
        config={
            "metadata": {"user_id": user_id},
            "run_name": f"request-{user_id}",
        },
    )
